module RefModule(  
    input wire clk,  
    input wire enable,  
    input wire gpio_in,  
    output reg gpio_out  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (enable)  
            gpio_out <= gpio_in;  
    end  
endmodule
